import React, { createContext, useContext, useState, useEffect } from 'react';
import { useUser, useAuth as useClerkAuth } from '@clerk/clerk-react';
import { createClerkSupabaseClient, supabase as anonSupabase } from '../services/supabase';

const AuthContext = createContext();

export function useAuth() {
    return useContext(AuthContext);
}

export function AuthProvider({ children }) {
    const { user: clerkUser, isLoaded: clerkLoaded } = useUser();
    const { getToken, signOut } = useClerkAuth();

    const [userData, setUserData] = useState(null);
    const [loading, setLoading] = useState(true);

    const fetchUserProfile = async () => {
        if (!clerkUser) return;
        try {
            const token = await getToken({ template: 'supabase' });
            const supabase = createClerkSupabaseClient(token);

            const { data: profile, error } = await supabase
                .from('users')
                .select('*')
                .eq('clerk_user_id', clerkUser.id)
                .single();

            if (error && error.code !== 'PGRST116') {
                console.error("Error fetching user profile:", error);
            }

            setUserData(profile || null);
        } catch (err) {
            console.error("Error resolving Clerk token:", err);
            setUserData(null);
        }
    };

    useEffect(() => {
        if (clerkLoaded) {
            if (clerkUser) {
                fetchUserProfile().then(() => setLoading(false));
            } else {
                setUserData(null);
                setLoading(false);
            }
        }
    }, [clerkUser, clerkLoaded]);

    const logout = async () => {
        await signOut();
    };

    const value = {
        currentUser: clerkUser,
        userData,
        logout,
        refreshUserData: fetchUserProfile
    };

    return (
        <AuthContext.Provider value={value}>
            {!loading && clerkLoaded && children}
        </AuthContext.Provider>
    );
}

import React, { useState } from 'react';
import { SignIn, SignUp } from '@clerk/clerk-react';
import { motion } from 'framer-motion';

export default function Auth() {
    const [isLogin, setIsLogin] = useState(true);

    return (
        <div className="container flex-center" style={{ minHeight: '100vh', padding: '2rem' }}>
            <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5 }}
                style={{ width: '100%', display: 'flex', justifyContent: 'center' }}
            >
                {isLogin ? (
                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                        <SignIn fallbackRedirectUrl="/" />
                        <button
                            type="button"
                            className="btn-ghost"
                            style={{ marginTop: '1.5rem', border: 'none', background: 'transparent', padding: '0.5rem', cursor: 'pointer', fontSize: '0.875rem' }}
                            onClick={() => setIsLogin(false)}
                        >
                            Don't have an account? Sign Up
                        </button>
                    </div>
                ) : (
                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                        <SignUp fallbackRedirectUrl="/onboarding" />
                        <button
                            type="button"
                            className="btn-ghost"
                            style={{ marginTop: '1.5rem', border: 'none', background: 'transparent', padding: '0.5rem', cursor: 'pointer', fontSize: '0.875rem' }}
                            onClick={() => setIsLogin(true)}
                        >
                            Already have an account? Sign In
                        </button>
                    </div>
                )}
            </motion.div>
        </div>
    );
}

import React, { useState, useRef, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { supabase } from '../services/supabase';
import CryptoJS from 'crypto-js';
import { motion, AnimatePresence } from 'framer-motion';

const ENCRYPTION_KEY = import.meta.env.VITE_ENCRYPTION_KEY || 'my-secret-key-123';
const encrypt = (text) => CryptoJS.AES.encrypt(text, ENCRYPTION_KEY).toString();

export default function Chat() {
    const { userData } = useAuth();
    const [messages, setMessages] = useState([
        { role: "assistant", content: "Hello. I am here to listen and help you work through what you're feeling using Cognitive Behavioral Therapy principles. How are you doing today?" }
    ]);
    const [input, setInput] = useState("");
    const [loading, setLoading] = useState(false);
    const scrollRef = useRef(null);

    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [messages]);

    const handleSend = async (e) => {
        e.preventDefault();
        if (!input.trim() || loading) return;

        const userMessage = input.trim();
        setInput("");

        const suicideKeywords = ['suicide', 'kill myself', 'end it', 'die', 'hurt myself'];
        const isCrisis = suicideKeywords.some(kw => userMessage.toLowerCase().includes(kw));

        if (isCrisis) {
            setMessages(prev => [...prev, { role: "user", content: userMessage }, {
                role: "assistant",
                content: "CRISIS EXCLUSION PROTOCOL: It sounds like you are in distress. Please seek immediate help.\n- SURPIN: 0908 021 7555\n- Mentally Aware Nigeria: 0809 111 6264\n- She Writes Woman: 0800 800 2000"
            }]);
            return;
        }

        setMessages(prev => [...prev, { role: "user", content: userMessage }]);
        setLoading(true);

        try {
            const encryptedMessage = encrypt(userMessage);

            const { data, error } = await supabase.functions.invoke('chat', {
                body: { message: userMessage, history: messages, religion: userData?.religion || 'prefer_not_to_say' }
            });

            if (error) {
                throw new Error(error.message);
            }

            if (data && data.reply) {
                const aiReply = data.reply;
                const encryptedReply = encrypt(aiReply);
                setMessages(prev => [...prev, { role: "assistant", content: aiReply }]);

                if (userData?.id) {
                    await supabase.from('chat_messages').insert([{
                        user_id: userData.id,
                        encrypted_message: encryptedMessage,
                        encrypted_response: encryptedReply
                    }]);
                }
            }
        } catch (error) {
            console.error("Chat error:", error);
            setMessages(prev => [...prev, { role: "assistant", content: "Sorry, I am having trouble connecting right now. Please try again." }]);
        }
        setLoading(false);
    };

    return (
        <div className="container" style={{ height: 'calc(100vh - 70px)', display: 'flex', flexDirection: 'column', paddingTop: '1rem', paddingBottom: '1rem' }}>
            <div className="glass-panel" style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
                <div style={{ borderBottom: '1px solid var(--glass-border)', paddingBottom: '1rem', marginBottom: '1rem' }}>
                    <h2 className="text-primary">Therapy Session</h2>
                    <p className="text-muted" style={{ fontSize: '0.875rem' }}>AI CBT Chatbot ÔÇó Mild/Moderate Support</p>
                </div>

                <div ref={scrollRef} style={{ flex: 1, overflowY: 'auto', paddingRight: '1rem', display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                    <AnimatePresence>
                        {messages.map((msg, idx) => (
                            <motion.div
                                key={idx}
                                initial={{ opacity: 0, y: 10 }}
                                animate={{ opacity: 1, y: 0 }}
                                style={{
                                    alignSelf: msg.role === 'user' ? 'flex-end' : 'flex-start',
                                    background: msg.role === 'user' ? 'var(--primary)' : 'rgba(255,255,255,0.05)',
                                    padding: '1rem',
                                    borderRadius: '12px',
                                    maxWidth: '80%',
                                    lineHeight: '1.5',
                                    border: msg.role === 'user' ? 'none' : '1px solid var(--glass-border)'
                                }}>
                                {msg.content.split('\n').map((line, i) => (
                                    <React.Fragment key={i}>
                                        {line}
                                        {i !== msg.content.split('\n').length - 1 && <br />}
                                    </React.Fragment>
                                ))}
                            </motion.div>
                        ))}
                    </AnimatePresence>
                    {loading && (
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            style={{ alignSelf: 'flex-start', color: 'var(--text-muted)' }}
                        >
                            <i>assistant is typing...</i>
                        </motion.div>
                    )}
                </div>

                <form onSubmit={handleSend} style={{ display: 'flex', gap: '1rem', marginTop: '1rem', borderTop: '1px solid var(--glass-border)', paddingTop: '1rem' }}>
                    <input
                        type="text"
                        className="input-field"
                        placeholder="Type your message..."
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        disabled={loading}
                        style={{ flex: 1, margin: 0 }}
                    />
                    <button type="submit" className="btn btn-primary" disabled={loading || !input.trim()}>
                        Send
                    </button>
                </form>
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../services/supabase';
import { motion } from 'framer-motion';

export default function Dashboard() {
    const { currentUser, userData, logout } = useAuth();
    const navigate = useNavigate();
    const [mood, setMood] = useState('');
    const [logging, setLogging] = useState(false);
    const [dailyVerse, setDailyVerse] = useState('');
    const [loadingVerse, setLoadingVerse] = useState(false);

    useEffect(() => {
        const fetchDailyVerse = async () => {
            if (!userData || !userData.eligible_for_chatbot) return;

            const today = new Date().toISOString().split('T')[0];
            const { data, error } = await supabase
                .from('daily_verses')
                .select('*')
                .eq('user_id', userData.id)
                .eq('date_served', today)
                .single();

            if (data) {
                setDailyVerse(data.verse_text);
            } else {
                setLoadingVerse(true);
                try {
                    const res = await supabase.functions.invoke('daily-verse', {
                        body: { religion: userData.religion || 'prefer_not_to_say' }
                    });

                    if (res.error) throw res.error;
                    const verse = res.data.verse;

                    await supabase.from('daily_verses').insert([{
                        user_id: userData.id,
                        verse_text: verse,
                        religion: userData.religion || 'prefer_not_to_say',
                        date_served: today
                    }]);

                    setDailyVerse(verse);
                } catch (err) {
                    console.error("Failed to fetch daily verse:", err);
                    setDailyVerse("Every day is a new beginning. Take a deep breath and start again.");
                }
                setLoadingVerse(false);
            }
        };

        fetchDailyVerse();
    }, [userData, currentUser]);

    const getSeverity = (score) => {
        if (score <= 4) return "Minimal Depression";
        if (score <= 9) return "Mild Depression";
        if (score <= 14) return "Moderate Depression";
        if (score <= 19) return "Moderately Severe Depression";
        return "Severe Depression";
    };

    const handleMoodSubmit = async (e) => {
        e.preventDefault();
        if (!mood) return;
        setLogging(true);
        try {
            const { error } = await supabase
                .from('mood_logs')
                .insert([{ user_id: userData.id, mood: mood }]);

            if (error) throw error;

            alert('Mood logged successfully!');
            setMood('');
        } catch (err) {
            console.error(err);
            alert('Failed to log mood.');
        }
        setLogging(false);
    };

    return (
        <div className="container" style={{ paddingTop: '2rem', paddingBottom: '2rem' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                <h2>Your Dashboard</h2>
                <button onClick={logout} className="btn-ghost" style={{ padding: '0.5rem 1rem' }}>Sign Out</button>
            </div>

            {userData?.needs_crisis_intervention && (
                <div style={{ background: 'rgba(255,0,0,0.1)', border: '1px solid #ff6b6b', padding: '1.5rem', borderRadius: '8px', marginBottom: '2rem' }}>
                    <h3 style={{ color: '#ff6b6b', marginBottom: '0.5rem' }}>Important Notice</h3>
                    <p style={{ color: '#fff' }}>Your recent assessment indicates you may need more intensive support than this chatbot can provide. Please contact a professional healthcare provider or reach out to emergency services.</p>
                </div>
            )}

            {dailyVerse && (
                <motion.div
                    initial={{ opacity: 0, scale: 0.95 }}
                    animate={{ opacity: 1, scale: 1 }}
                    transition={{ duration: 0.6 }}
                    style={{ background: 'linear-gradient(135deg, rgba(241, 225, 148, 0.1), rgba(91, 14, 20, 0.2))', border: '1px solid var(--secondary)', padding: '1.5rem', borderRadius: '12px', marginBottom: '2rem', textAlign: 'center' }}
                >
                    <h3 className="text-secondary" style={{ marginBottom: '0.5rem', fontSize: '0.875rem', textTransform: 'uppercase', letterSpacing: '1px' }}>Daily Reassurance</h3>
                    <p style={{ fontSize: '1.25rem', fontStyle: 'italic', fontWeight: '500' }}>"{dailyVerse}"</p>
                </motion.div>
            )}

            {loadingVerse && (
                <div style={{ textAlign: 'center', marginBottom: '2rem', color: 'var(--text-muted)' }}>Generating your daily reassurance...</div>
            )}

            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '2rem' }}>

                {/* Assessment Card */}
                <div className="glass-panel">
                    <h3 className="text-secondary" style={{ marginBottom: '1rem' }}>Latest Assessment</h3>
                    {userData?.phq9_score !== undefined && userData?.phq9_score !== null ? (
                        <>
                            <div style={{ fontSize: '3rem', fontWeight: 'bold', color: 'var(--primary)' }}>
                                {userData.phq9_score} <span style={{ fontSize: '1rem', color: 'var(--text-muted)' }}>/ 27</span>
                            </div>
                            <p style={{ marginTop: '0.5rem', fontWeight: '500' }}>
                                {getSeverity(userData.phq9_score)}
                            </p>
                            {userData.last_assessment_date && (
                                <p className="text-muted" style={{ fontSize: '0.875rem', marginTop: '1rem' }}>
                                    Last assessed: {new Date(userData.last_assessment_date).toLocaleDateString()}
                                </p>
                            )}
                        </>
                    ) : (
                        <p>No assessment recorded.</p>
                    )}
                </div>

                {/* Therapy Session Card */}
                <div className="glass-panel" style={{ display: 'flex', flexDirection: 'column', justifyContent: 'space-between' }}>
                    <div>
                        <h3 className="text-secondary" style={{ marginBottom: '1rem' }}>CBT Session</h3>
                        <p className="text-muted">Engage in an AI-powered Cognitive Behavioral Therapy session integrated with spiritual support to help manage your symptoms.</p>
                    </div>
                    <button onClick={() => navigate('/chat')} className="btn btn-primary" style={{ marginTop: '2rem' }}>
                        Start Chat Session
                    </button>
                </div>

                {/* Mood Log Card */}
                <div className="glass-panel" style={{ gridColumn: '1 / -1' }}>
                    <h3 className="text-secondary" style={{ marginBottom: '1rem' }}>Daily Mood Tracker</h3>
                    <p className="text-muted" style={{ marginBottom: '1rem' }}>Log your mood daily to help track your cognitive restructuring progress.</p>
                    <form onSubmit={handleMoodSubmit} style={{ display: 'flex', gap: '1rem' }}>
                        <select
                            className="input-field"
                            value={mood}
                            onChange={e => setMood(e.target.value)}
                            style={{ flex: 1, margin: 0 }}
                            required
                        >
                            <option value="" disabled>Select how you're feeling...</option>
                            <option value="great">Great</option>
                            <option value="good">Good</option>
                            <option value="okay">Okay</option>
                            <option value="bad">Bad</option>
                            <option value="awful">Awful</option>
                        </select>
                        <button type="submit" className="btn btn-secondary" disabled={logging || !mood}>
                            {logging ? 'Saving...' : 'Log Mood'}
                        </button>
                    </form>
                </div>

            </div>
        </div>
    );
}

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { useAuth } from '../contexts/AuthContext';
import { useUser } from '@clerk/clerk-react';
import { createClerkSupabaseClient } from '../services/supabase';

export default function Onboarding() {
    const [name, setName] = useState('');
    const [religion, setReligion] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    const navigate = useNavigate();
    const { user } = useUser();
    const { refreshUserData } = useAuth();

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');

        if (!name || !religion) {
            setError('Please fill out all fields.');
            return;
        }

        setLoading(true);

        try {
            const token = await window.Clerk.session?.getToken({ template: 'supabase' });
            const supabase = createClerkSupabaseClient(token);

            const { error: insertError } = await supabase
                .from('users')
                .insert({
                    clerk_user_id: user.id,
                    name: name,
                    email: user.primaryEmailAddress?.emailAddress,
                    religion: religion
                });

            if (insertError) {
                throw new Error(insertError.message || "Failed to save profile.");
            }

            await refreshUserData();
            navigate('/');
        } catch (err) {
            console.error("Onboarding error:", err);
            setError(err.message || 'An error occurred during onboarding.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="container flex-center" style={{ minHeight: '100vh' }}>
            <motion.div
                className="glass-panel"
                style={{ width: '100%', maxWidth: '400px' }}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5 }}
            >
                <h2 className="text-center text-secondary" style={{ marginBottom: '1.5rem', fontSize: '2rem' }}>
                    Welcome to AI Therapist
                </h2>
                <p className="text-center text-muted" style={{ marginBottom: '2rem' }}>
                    Let's set up your profile for personalized support.
                </p>

                {error && (
                    <div style={{ background: 'rgba(255,0,0,0.1)', color: '#ff6b6b', padding: '0.75rem', borderRadius: '8px', marginBottom: '1.5rem', border: '1px solid rgba(255,0,0,0.2)', fontSize: '0.875rem' }}>
                        {error}
                    </div>
                )}

                <form onSubmit={handleSubmit}>
                    <div className="input-group" style={{ marginBottom: '1.5rem' }}>
                        <label className="input-label">Preferred Name / Alias</label>
                        <input
                            type="text"
                            className="input-field"
                            placeholder="How should we call you?"
                            value={name}
                            onChange={(e) => setName(e.target.value)}
                            required
                        />
                    </div>

                    <div className="input-group" style={{ marginBottom: '2rem' }}>
                        <label className="input-label">Religion / Background</label>
                        <p className="text-muted" style={{ fontSize: '0.8rem', marginBottom: '8px' }}>Used for spiritually adapted CBT responses</p>
                        <select
                            className="input-field"
                            value={religion}
                            onChange={(e) => setReligion(e.target.value)}
                            required
                            style={{ backgroundColor: 'var(--glass-bg)', color: 'white' }}
                        >
                            <option value="" disabled>Select your background</option>
                            <option value="christian">Christian</option>
                            <option value="muslim">Muslim</option>
                            <option value="prefer_not_to_say">Prefer not to say</option>
                        </select>
                    </div>

                    <button
                        type="submit"
                        className="btn btn-primary"
                        style={{ width: '100%' }}
                        disabled={loading}
                    >
                        {loading ? 'Saving...' : 'Complete Setup'}
                    </button>
                </form>
            </motion.div>
        </div>
    );
}
